import{_ as e,o as a,c as t,j as r,a as p,a1 as d}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"灾厄幻星","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/3.心智类/灾厄幻星.md","filePath":"4.资源分区/1.血统与训练/3.心智类/灾厄幻星.md"}'),n={name:"4.资源分区/1.血统与训练/3.心智类/灾厄幻星.md"};function s(o,b,c,l,_,i){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"灾厄幻星",tabindex:"-1"},[p("灾厄幻星 "),r("a",{class:"header-anchor",href:"#灾厄幻星","aria-label":'Permalink to "灾厄幻星"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风026")])])],-1),d('<h1 id="灾厄幻星-1" tabindex="-1">灾厄幻星 <a class="header-anchor" href="#灾厄幻星-1" aria-label="Permalink to &quot;灾厄幻星&quot;">​</a></h1><p>灾厄幻星<br> 这是一个来自爱的祝福，这是一个来自爱的诅咒。<br> 对你不善者将永堕灾祸，<br> 对你善良者将永避灾祸，<br> 愿你幸福。<br> 愿你成为闪亮的星辰，<br> 永远闪亮，永远快乐。<br> 魔幻本质</p><p>D+600<br> 扫把星<br> [转瞬即逝的灾厄开幕]<br> 灾厄之始：你逐渐开始知道如何操作自己的灾厄之力来应对你的敌人。<br> 强化时选择恶心，耳鸣，目眩，疲乏四种异常之一。<br> 你可以在战斗开始时消耗1点意志，本场战斗你的攻击附带等量你选择的诅咒来源的异常点，以本次攻击出目作为dc，意志豁免。<br> 黑蚀之击：灾厄已经缠绕于他人身上，只有自己认同自己对自身带来灾厄的决心，才能对敌人造成更猛烈的打击。<br> 当你攻击的对象携带有由你造成的异常点或异常状态时，你的攻击额外增加传奇决心*1的破甲，在计算破防效果后若是破甲仍然有剩余，则等额转变为攻击上的增强加值，至多转变等于传奇决心*1的破甲。<br> 噬厄之躯：灾厄涌入残破的身躯，却带来恢复的力量。<br> 你获得由灾厄之力带来的快速医疗1（12医疗点）</p><p>C+1200<br> 天灾孤月<br> [如同潮汐般的灾厄袭来]<br> 灾厄之潮：你的攻击牵动如同潮水般的灾厄裹挟着敌人。<br> 灾厄在你的手中会化为潮水浸染敌人，你的肉搏或白刃攻击将会带有以本次攻击出目作为dc，意志豁免，若失败则承受潮湿效果，这是一个c级诅咒来源的效果，持续一个场景。<br> 灾厄共鸣：随着你手中产生的灾厄散布，你的肉体将不再残破<br> 进入战斗后，灾厄之力将如潮水一般由你的身体里蔓延开来，具体表现是越靠近你越能感觉到一种不祥的气质在扩张，每两轮过去，你临时获得快速医疗1（12医疗点），最多获得4次，战斗结束消失。</p><p>B+2400<br> 逆行重华<br> [逆行的岁星，灾厄的化身]<br> 灾厄具现：将无形的灾厄化为漆黑的流体，发出带来灾祸的攻击。<br> 强化时选择冻结，麻痹，晕眩，剧痛，晶化五种异常之一。<br> 以一个标准动作发动，流体的灾厄化为触手缠绕进你的攻击之上，你进行一次近战攻击，现在开始本场战斗你的攻击附带等量你选择的诅咒来源的异常点，以本次攻击出目作为dc，意志豁免。且获得2点遮蔽防御，持续一个场景。<br> 命运扭曲：通过灾厄的流转，你一窥命运的秘密。<br> 你免疫B级命运来源的效果。<br> 无竭涡流：灾厄会将你的所有敌人都卷进去，这是你的诅咒，也是最大的祝福。<br> 你现在【灾厄之潮】造成的潮湿效果改为B级，当你攻击的对象携带有由你造成的异常点或异常状态时，会带有以本次攻击出目作为dc，意志豁免，若失败则该单位会从分离出一个额头缝着自己名字的，带有该单位一些灵魂的吐着黑色液体的等身布娃娃在原地持续一个场景，攻击娃娃也会攻击到本体，这是一个B级诅咒来源的【魂牵】效果。</p><p>A+4800<br> 终焉黑日<br> [灾厄之源，虚拟天体]<br> 灾厄幻灵：你即是存活的灾厄，即使离开凡间的肉体也只是暂时的。<br> 在你死亡后，你可以从黑猫，乌鸦两种生物中选择一个，化为对应的灵体形态，体积不变，除了观察和移动外无法进行更多的动作，结构值等同于你的意志力，经过了6天的第6个小时的6分钟的第6秒时，你复活，如果形式被摧毁则复活失败，这是一个诅咒来源的A级的复活效果。<br> 灾厄化身：黑色的涡流彻底将自身包裹，化为迫近的风暴。<br> 在发动【灾厄具现】时，你与灾厄暂时融合，化为黑色的涡流，该血统造成的第一档异常点现在升级为第四档异常点，免疫擒抱状态 ，持续一个场景。<br> 无避之灾：你的灾厄已经深入灵魂，难以根除<br> 现在，当你使用该血统提供的能力（不包括下属技艺）对敌人施加异常点数或异常状态时，你还会同时使敌人在对该次异常状态或异常点数的意志豁免上受到A级诅咒来源的【劣化2】<br> 你的【命运扭曲】改为免疫A级命运来源的效果<br> 毁天灭地：终焉的灾祸，无人可以逃离的地狱之地，就此展开<br> 以一个移动动作发动，你将灾厄之力轰入大地，在下轮开始时，以你为中心的，半径为126米范围的圆形区域将被灾厄之力变为喷发火山地形，这是一个A级的环境效果，表现为地里喷出巨量的高温黑色污泥，持续一个场景，同时间只能存在一个被这样改变所出现的喷发火山。</p><p>灾厄幻星下属技艺<br> 报应之手<br> D+500<br> 将灾厄聚集于双手之上，给予敌人又一次死亡。<br> 以一个自由动作消耗1点意志，赋予你的近战攻击或肉搏攻击附带一点诅咒来源不可豁免的燃烧异常点，持续一场景，可以以一个自由动作提前中止。</p><p>灾厄幻星下属魔法物品</p><p>逆飞的烟火<br> 魔幻本质<br> 魔法物品<br> 自然派系<br> 使用激活型</p><p>价格：D+500/C+1000/B+2000【差价升级】</p><p>由于为差价升级，故高等级不再重复描述前一级效果。</p><p>激活：需要一只手握持其才能激活，进行一次消耗了移动动作的移动时可以激活它，但以此法进行的移动不能释放任何的移动技，每次激活的效果持续一场景。需要时可将其作为一把武器伤害0L，体积3的长棍使用。<br> 特殊的，逆飞的烟火等级为B级时，激活方式改为使用自由动作激活。<br> 一把漆黑的木头扫把，但扫把头是由一条条闪着星光的星之枝桠做成的。挥舞起来犹如满天流星降临。<br> 该魔法物品赋予的能力在判断提供来源时视为是来自灾厄幻星的血统。</p><p>D级：【星尘之尾】<br> 前提：扫把星<br> [逝去灾厄留下的尘灰]<br> 灾厄之遗：灾厄逝去，留下狼藉。<br> 购买时选择你未在【灾厄之始】中的剩下三种异常之一。 <br> 当你触发【灾厄之始】的效果时，本场战斗你的攻击再附带等量你在【星尘之尾】选择的诅咒来源的异常点，以本次攻击出目作为dc，意志豁免。<br> 厄命流：灾厄与你灵魂同生。<br> 【噬厄之躯】提供的快速医疗的医疗池上限提高8点，只要【噬厄之躯】提供的快速医疗的医疗池不空，你的伤势不会自然恶化。</p><p>C级：【隐月之晦】<br> 前提：天灾孤月<br> [血月落下的疯狂之末]<br> 灾厄之汐：月辉作为媒介，再度引动灾难。<br> 现在你的所有攻击都能触发【灾厄之潮】而非仅是肉搏或白刃攻击。<br> 灾厄谐振：灾厄的化身在昨，在现，在明。<br> 【灾厄共鸣】改为：进入战斗后，第一轮过去，【噬厄之躯】额外获得临时快速医疗2（24医疗点），第二轮过去，【噬厄之躯】再额外获得临时快速医疗3（36医疗点），战斗结束消失。</p><p>B级：【岁阴之临】<br> 前提：逆行重华<br> [祸神临，岁月转]<br> 【吉祸相印】：天之祸神，地之灾物。<br> 现在你需要触发【灾厄具现】时，以一个标准动作发动，进行一次任意方式的攻击便可触发，而非仅能依靠近战攻击。<br> 【太岁神】：当年十二支方向的方位神，与在该方位所作所为之吉凶相关，即民俗传说中，冲太岁，犯太岁等说法的来源，当然经过流传，大部分人对于太岁还是只保有祸神的印象。<br> 现在你在激活该物品时，你具有【神】特质，具有【神话生物】特质。<br> 【凶神】：太岁在古代崇高的地位使百姓流传出以自己低微的身份接触便会遭遇厄运，在各种民俗书籍的对于如何避免犯太岁及犯太岁的后果记录下，太岁开始拥有了凶神的概念。<br> 每轮一次，当有不知天高地厚的家伙向你发起攻击时，你可以选择显露自己的凶神本质，使对你发起攻击的单位产生畏惧，本次攻击需要重骰且取出目更低的效果为结果。<br> 同时，你主动的接触也可以将祸的力量在敌人身上体现，在【灾厄具现】触发状态下，目标被你的攻击需要进行一次意志豁免，以本次攻击出目作为dc，失败则将被太岁诅咒，生命力将被剥夺，目标在伤势恶化时，除非其韧性值完全恢复，否则无法自动稳定，且使用恢复生命值的能力时，其恢复数值减少3点。<br> 这是一个B级重伤效果，需要判断来源时，为诅咒来源。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const m=e(n,[["render",s]]);export{f as __pageData,m as default};
